468	            Ok(_) => match stream.synchronize() {
469	                Ok(()) => {
470	                    let results: Vec<u32> = reduce_output.to_host_vec(&stream).unwrap();
471	                    let expected_sum = (1..=cluster_size).map(|i| i * 10).sum::<u32>();
472	                    println!("Result: {}, expected: {}", results[0], expected_sum);
473	                    results[0] == expected_sum
