6	#![allow(clippy::approx_constant)]
7	
8	//! Unified Atomics Test Example
9	//!
10	//! Comprehensive test suite for sound atomic operations:
11	//!
12	//! **Phase 1 (DeviceAtomicU32/I32, load/store/fetch_add/CAS):**
13	//!  1. `atomic_fetch_add_test` -- DeviceAtomicU32 fetch_add (Relaxed)
14	//!  2. `atomic_load_store_test` -- DeviceAtomicU32 load/store (Acquire/Release)
15	//!  3. `atomic_cas_test` -- DeviceAtomicU32 compare_exchange (AcqRel)
16	//!  4. `atomic_fetch_add_acqrel_test` -- fence-splitting workaround (AcqRel)
17	//!  5. `atomic_fetch_add_seqcst_test` -- fence.sc pattern (SeqCst)
18	//!  6. `atomic_i32_test` -- DeviceAtomicI32 fetch_add + compare_exchange
19	//!  7. `atomic_multiblock_test` -- device-scope atomics across CTAs
20	//!
21	//! **Phase 2 (new types + new RMW ops):**
22	//!  8. `atomic_u64_fetch_add_test` -- DeviceAtomicU64 fetch_add (64-bit)
23	//!  9. `atomic_i64_test` -- DeviceAtomicI64 fetch_add + compare_exchange
24	//! 10. `atomic_fetch_sub_test` -- DeviceAtomicU32 fetch_sub
25	//! 11. `atomic_bitwise_test` -- fetch_and, fetch_or, fetch_xor
26	//! 12. `atomic_swap_test` -- DeviceAtomicU32 swap (exchange)
27	//! 13. `atomic_minmax_test` -- DeviceAtomicI32 fetch_min / fetch_max (signed)
28	//! 14. `atomic_f32_fetch_add_test` -- DeviceAtomicF32 fetch_add (float)
29	//! 15. `atomic_f64_fetch_add_test` -- DeviceAtomicF64 fetch_add (64-bit float)
30	//! 16. `atomic_f32_swap_test` -- DeviceAtomicF32 swap (float exchange)
31	//! 17. `atomic_unsigned_minmax_test` -- DeviceAtomicU32 fetch_min/max (UMin/UMax)
32	//! 18. `atomic_block_scope_test` -- BlockAtomicU32 fetch_add (.cta scope, Relaxed)
33	//! 19. `atomic_block_scope_acqrel_test` -- BlockAtomicU32 fetch_add (.cta scope, AcqRel)
34	//! 20. `core_atomic_fetch_add_test` -- core::sync::atomic::AtomicU32 (system scope)
35	//!
36	//! Build and run with:
37	//!   cargo oxide run atomics
38	
39	use core::sync::atomic::Ordering;
40	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
41	use cuda_device::atomic::{
42	    AtomicOrdering, BlockAtomicU32, DeviceAtomicF32, DeviceAtomicF64, DeviceAtomicI32,
43	    DeviceAtomicI64, DeviceAtomicU32, DeviceAtomicU64,
44	};
45	use cuda_device::{DisjointSlice, kernel, thread};
46	use cuda_host::cuda_module;
47	
48	// =============================================================================
49	// KERNELS
50	// =============================================================================
51	#[cuda_module]
52	mod kernels {
53	    use super::*;
54	
55	    /// Test 1: Atomic fetch_add -- every thread atomically increments a counter.
56	    ///
57	    /// After N threads run, counter[0] should equal N.
58	    /// This tests the atomicrmw path with the fence-splitting workaround.
59	    #[kernel]
60	    pub fn atomic_fetch_add_test(counter: &[u32], mut out: DisjointSlice<u32>) {
61	        let gid = thread::index_1d();
62	
63	        // Get an DeviceAtomicU32 reference to counter[0] (shared access via interior mutability)
64	        let atomic_counter = unsafe { &*(counter.as_ptr() as *const DeviceAtomicU32) };
65	
66	        // Each thread atomically increments the counter and gets the old value
67	        let old = atomic_counter.fetch_add(1, AtomicOrdering::Relaxed);
68	
69	        // Store the old value so we can verify uniqueness on the host
70	        if let Some(out_elem) = out.get_mut(gid) {
71	            *out_elem = old;
72	        }
73	    }
74	
75	    /// Test 2: Atomic load/store -- thread 0 stores a value, all threads load it.
76	    ///
77	    /// Uses Acquire/Release ordering for proper visibility:
78	    /// - Thread 0: store with Release (makes the write visible)
79	    /// - Other threads: load with Acquire (sees the Release'd write)
80	    #[kernel]
81	    pub fn atomic_load_store_test(flag: &[u32], mut out: DisjointSlice<u32>) {
82	        let tid = thread::threadIdx_x();
83	        let gid = thread::index_1d();
84	
85	        // Get an DeviceAtomicU32 reference to flag[0] (shared access via interior mutability)
86	        let atomic_flag = unsafe { &*(flag.as_ptr() as *const DeviceAtomicU32) };
87	
88	        // Thread 0 stores a sentinel value
89	        if tid == 0 {
90	            atomic_flag.store(42, AtomicOrdering::Release);
91	        }
92	
93	        // Barrier ensures all threads see the store
94	        thread::sync_threads();
95	
96	        // All threads load the value
97	        let val = atomic_flag.load(AtomicOrdering::Acquire);
98	        if let Some(out_elem) = out.get_mut(gid) {
99	            *out_elem = val;
100	        }
101	    }
102	
103	    /// Test 3: Atomic compare_exchange -- only one thread wins the CAS race.
104	    ///
105	    /// All threads try to CAS 0 -> their_tid. Exactly one succeeds.
106	    #[kernel]
107	    pub fn atomic_cas_test(winner: &[u32], mut out: DisjointSlice<u32>) {
108	        let tid = thread::threadIdx_x();
109	        let gid = thread::index_1d();
110	
111	        // Get an DeviceAtomicU32 reference to winner[0] (shared access via interior mutability)
112	        let atomic_winner = unsafe { &*(winner.as_ptr() as *const DeviceAtomicU32) };
113	
114	        // Try to be the first thread to swap 0 -> (tid + 1)
115	        // We use tid+1 so that thread 0's success value (1) differs from the
116	        // initial value (0).
117	        let result = atomic_winner.compare_exchange(
118	            0,
119	            tid + 1,
120	            AtomicOrdering::AcqRel,
121	            AtomicOrdering::Relaxed,
