    /// Pick a specific binary in a multi-bin package
    #[arg(long)]
    bin: Option<String>,
    /// Show verbose compilation output
    #[arg(short, long)]
    verbose: bool,
    /// Disable implicit FMA contraction in device codegen.
    /// Also settable via CUDA_OXIDE_NO_FMA=1.
    #[arg(long)]
    no_fmad: bool,
